
(function () {
const heroDesert = "https://images.unsplash.com/photo-1509316975850-ff9c5deb0cd9?w=1920&q=80";
const heroMountains ="https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?w=1920&q=80";
const heroBeach = "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1920&q=80";
const featuresLandscape = "data:image/jpeg;base64,";
const problemCluttered = "data:image/jpeg;base64,";
const solutionClean = "data:image/jpeg;base64,";

const slides = [
  {
    image: heroDesert,
    label: '01 Sandy Mountains Tour',
    title: 'Sandy\nMountains',
    description: 'Explore the Moroccan Sahara Desert on a 3-day safari from Marrakech to Merzouga. Spend the night at a Bedouin camp in the Erg Chebbi dunes.',
    panelSide: 'left',
  },
  {
    image: heroMountains,
    label: '02 Alpine Reflections',
    title: 'Alpine\nReflections',
    description: 'Witness snow-capped peaks mirrored in crystal-clear alpine lakes at sunrise. A 5-day guided trek through untouched wilderness.',
    panelSide: 'right',
  },
  {
    image: heroBeach,
    label: '03 Tropical Paradise',
    title: 'Tropical\nParadise',
    description: 'Discover pristine beaches with turquoise waters and golden sunsets. An exclusive 7-day island-hopping experience in the Indian Ocean.',
    panelSide: 'left',
  },
];

let current = 0;
let autoTimer = null;

const bgsEl    = document.getElementById('hero-bgs');
const panelsEl = document.getElementById('hero-panels');
const titleEl  = document.getElementById('hero-title');
const dotsEl   = document.getElementById('hero-dots');

if (!bgsEl || !panelsEl || !titleEl || !dotsEl) return;

slides.forEach((s, i) => {
  
  const bg = document.createElement('div');
  bg.className = 'hero-bg-slide';
  bg.innerHTML = `<img src="${s.image}" alt="${s.title.replace('\n',' ')}" width="1920" height="1080" />`;
  bgsEl.appendChild(bg);

  
  const panel = document.createElement('div');
  panel.className = 'hero-panel' + (s.panelSide === 'right' ? ' slide-from-right' : '');
  const mParts = s.title.split('\n');
  const mirrorHTML = `<span class="title-line-1">${mParts[0]}</span><br><span class="title-line-2">${mParts[1] || ''}</span>`;
  panel.innerHTML = `
    <div class="panel-title-mirror">${mirrorHTML}</div>
    <div class="panel-inner">
      <p class="slide-label">${s.label}</p>
      <p class="slide-desc">${s.description}</p>
      <button class="btn-outline-hero">More details</button>
    </div>`;
  panelsEl.appendChild(panel);

  
  const dot = document.createElement('button');
  dot.className = 'hero-dot';
  dot.setAttribute('aria-label', `Go to slide ${i+1}`);
  dot.addEventListener('click', () => goTo(i));
  dotsEl.appendChild(dot);
});

const bgEls    = [...bgsEl.querySelectorAll('.hero-bg-slide')];
const panelEls = [...panelsEl.querySelectorAll('.hero-panel')];
const dotEls   = [...dotsEl.querySelectorAll('.hero-dot')];

function showSlide(idx) {
  const prev = current;
  current = (idx + slides.length) % slides.length;

  
  bgEls[prev].classList.remove('active');
  bgEls[current].classList.add('active');
  
  const img = bgEls[current].querySelector('img');
  const clone = img.cloneNode(true);
  bgEls[current].replaceChild(clone, img);

  
  panelEls[prev].classList.remove('active');

  
  titleEl.classList.remove('active');
  setTimeout(() => {
    const parts = slides[current].title.split('\n');
    titleEl.innerHTML = `<span class="title-line-1">${parts[0]}</span><br><span class="title-line-2">${parts[1] || ''}</span>`;
    titleEl.classList.add('active');
  }, 350);

  
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      panelEls[current].classList.add('active');
    });
  });

  
  dotEls.forEach((d, i) => d.classList.toggle('active', i === current));
}

function goTo(idx) {
  if (idx === current) return;
  resetTimer();
  showSlide(idx);
}

function next() { showSlide(current + 1); }
function prev() { showSlide(current - 1); }

function resetTimer() {
  clearInterval(autoTimer);
  autoTimer = setInterval(next, 6000);
}

document.getElementById('hero-next').addEventListener('click', () => { next(); resetTimer(); });
document.getElementById('hero-prev').addEventListener('click', () => { prev(); resetTimer(); });

const initParts = slides[0].title.split('\n');
titleEl.innerHTML = `<span class="title-line-1">${initParts[0]}</span><br><span class="title-line-2">${initParts[1] || ''}</span>`;
bgEls[0].classList.add('active');
panelEls[0].classList.add('active');
dotEls[0].classList.add('active');
titleEl.classList.add('active');
resetTimer();
})();

const revealEls = document.querySelectorAll('.reveal');
const observer  = new IntersectionObserver((entries) => {
  entries.forEach(e => {
    if (e.isIntersecting) {
      e.target.classList.add('visible');
      observer.unobserve(e.target);
    }
  });
}, { threshold: 0.12 });

revealEls.forEach(el => observer.observe(el));

(function() {
  var journeySection = document.getElementById('journey-features');
  var splitSets      = document.querySelectorAll('.split-set');
  var journeyCards   = document.querySelectorAll('.journey-card');
  var parallaxBgs    = document.querySelectorAll('.parallax-bg');
  var svgPath        = document.getElementById('journey-progress-path');
  var activeJourneyIdx = 0;

  window.addEventListener('scroll', function() {
    if (!journeySection) return;
    if (window.innerWidth <= 768) return; 
    var rect = journeySection.getBoundingClientRect();
    if (rect.bottom < 0 || rect.top > window.innerHeight) return;

    var totalScrollable = rect.height - window.innerHeight;
    var progress = -rect.top / totalScrollable;
    progress = Math.max(0, Math.min(1, progress));

    if (svgPath) {
      svgPath.style.strokeDashoffset = 100 - (progress * 100);
    }

    var newIdx = Math.floor(progress * 2.99);

    if (newIdx !== activeJourneyIdx) {
      activeJourneyIdx = newIdx;

      splitSets.forEach(function(set, i) {
        set.style.opacity = i === activeJourneyIdx ? 1 : 0;
        set.style.pointerEvents = i === activeJourneyIdx ? 'auto' : 'none';
      });

      journeyCards.forEach(function(card, i) {
        var inner = card.querySelector('.card-inner');
        var dot   = card.querySelector('.journey-dot');

        if (i === activeJourneyIdx) {
          inner.classList.replace('opacity-40', 'opacity-100');
          inner.classList.replace('scale-95',   'scale-100');
          dot.classList.add('scale-150', 'bg-white');
          if (i === 0) dot.classList.add('shadow-[0_0_15px_rgba(20,184,166,0.6)]');
          if (i === 1) dot.classList.add('shadow-[0_0_15px_rgba(16,185,129,0.6)]');
          if (i === 2) dot.classList.add('shadow-[0_0_15px_rgba(255,255,255,0.6)]');
        } else {
          inner.classList.replace('opacity-100', 'opacity-40');
          inner.classList.replace('scale-100',   'scale-95');
          dot.classList.remove(
            'scale-150', 'bg-white',
            'shadow-[0_0_15px_rgba(20,184,166,0.6)]',
            'shadow-[0_0_15px_rgba(16,185,129,0.6)]',
            'shadow-[0_0_15px_rgba(255,255,255,0.6)]'
          );
        }
      });

      parallaxBgs.forEach(function(bg, i) {
        bg.style.opacity = i === activeJourneyIdx ? 0.4 : 0;
      });
    }
  });

  
  var splitContainer = document.getElementById('split-container');
  var splitHandle    = document.getElementById('split-handle');
  var clipLayers     = document.querySelectorAll('.clip-layer');
  var isDraggingSplit = false;

  if (splitContainer && window.innerWidth > 768) {
    splitContainer.addEventListener('mousedown',  function() { isDraggingSplit = true;  document.body.style.userSelect = 'none'; });
    splitContainer.addEventListener('touchstart', function() { isDraggingSplit = true;  document.body.style.userSelect = 'none'; }, { passive: true });
    window.addEventListener('mouseup',  function() { isDraggingSplit = false; document.body.style.userSelect = 'auto'; });
    window.addEventListener('touchend', function() { isDraggingSplit = false; document.body.style.userSelect = 'auto'; });

    function moveDrag(e) {
      if (!isDraggingSplit) return;
      var rect    = splitContainer.getBoundingClientRect();
      var clientX = e.type.includes('touch') ? e.touches[0].clientX : e.clientX;
      var pos     = Math.max(5, Math.min(95, ((clientX - rect.left) / rect.width) * 100));
      splitHandle.style.left = pos + '%';
      clipLayers.forEach(function(layer) {
        layer.style.clipPath = 'polygon(0 0, ' + pos + '% 0, ' + pos + '% 100%, 0 100%)';
      });
    }

    window.addEventListener('mousemove', moveDrag);
    window.addEventListener('touchmove',  moveDrag, { passive: true });
  }
})();

(function() {
  function initScrollReveal(el, threshold) {
    if (!el) return;
    var obs = new IntersectionObserver(function(entries) {
      if (entries[0].isIntersecting) {
        el.classList.remove('hidden-reveal');
        el.classList.add('visible-reveal');
        obs.disconnect();
      }
    }, { threshold: threshold || 0.15 });
    obs.observe(el);
  }
  initScrollReveal(document.getElementById('aboutInner'),   0.15);
  initScrollReveal(document.getElementById('pricingInner'), 0.15);
  initScrollReveal(document.getElementById('contactInner'), 0.15);

  
  var video        = document.getElementById('aboutVideo');
  var playBtn      = document.getElementById('playBtn');
  var vcPlay       = document.getElementById('vcPlay');
  var vcMute       = document.getElementById('vcMute');
  var iconPlay     = document.getElementById('iconPlay');
  var iconPause    = document.getElementById('iconPause');
  var vcIconPlay   = document.getElementById('vcIconPlay');
  var vcIconPause  = document.getElementById('vcIconPause');
  var vcIconVolume = document.getElementById('vcIconVolume');
  var vcIconMute   = document.getElementById('vcIconMute');
  var progressFill = document.getElementById('progressFill');
  var videoContainer = document.getElementById('videoContainer');
  var progressTrack = document.querySelector('.about-progress-track');

  var playing = false;
  var muted   = true;

  if (video) {
    video.addEventListener('loadeddata', function() {
      var placeholder = document.querySelector('.about-placeholder');
      if (placeholder) placeholder.style.display = 'none';
    });
  }

  function setPlayState(state) {
    playing = state;
    if (iconPlay)    iconPlay.style.display    = playing ? 'none' : '';
    if (iconPause)   iconPause.style.display   = playing ? '' : 'none';
    if (vcIconPlay)  vcIconPlay.style.display  = playing ? 'none' : '';
    if (vcIconPause) vcIconPause.style.display = playing ? '' : 'none';
    if (videoContainer) {
      if (playing) videoContainer.classList.add('is-playing');
      else videoContainer.classList.remove('is-playing');
    }
  }

  function setMuteState(state) {
    muted = state;
    if (video) video.muted = muted;
    if (vcIconMute)   vcIconMute.style.display   = muted ? '' : 'none';
    if (vcIconVolume) vcIconVolume.style.display = muted ? 'none' : '';
  }

  function togglePlay() {
    if (!video) return;
    if (video.paused) { video.play(); setPlayState(true); }
    else              { video.pause(); setPlayState(false); }
  }

  function toggleMute() { setMuteState(!muted); }

  if (playBtn) playBtn.addEventListener('click', togglePlay);
  if (vcPlay)  vcPlay.addEventListener('click',  togglePlay);
  if (vcMute)  vcMute.addEventListener('click',  toggleMute);

  if (video) {
    video.addEventListener('loadeddata', function() {
      var placeholder = document.querySelector('.about-placeholder');
      if (placeholder) placeholder.style.display = 'none';
    });

    video.addEventListener('playing', function() {
      setPlayState(true);
    });

    video.addEventListener('pause', function() {
      setPlayState(false);
    });

    video.addEventListener('timeupdate', function() {
      if (video.duration && progressFill)
        progressFill.style.width = (video.currentTime / video.duration * 100) + '%';
    });

    video.addEventListener('ended', function() { setPlayState(false); });

    if (progressTrack) {
      progressTrack.style.cursor = 'pointer';
      progressTrack.addEventListener('click', function(e) {
        var rect = progressTrack.getBoundingClientRect();
        var percent = (e.clientX - rect.left) / rect.width;
        video.currentTime = percent * video.duration;
      });
    }

    
    fetch('/api/config/site')
      .then(function(r) { return r.json(); })
      .then(function(cfg) {
        if (cfg && cfg.about_video_url) {
          video.src = cfg.about_video_url;
          video.load();
          
          var placeholder = document.querySelector('.about-placeholder');
          if (placeholder) placeholder.style.display = 'none';
        }
      })
      .catch(function() {  });
  }
})();

(function() {
  var nav = document.querySelector('.hero-nav');
  if (!nav) return;
  function onScroll() {
    if (window.scrollY > 60) {
      nav.classList.add('scrolled');
    } else {
      nav.classList.remove('scrolled');
    }
  }
  window.addEventListener('scroll', onScroll, { passive: true });
  onScroll(); 
})();
